/**
 * Generate Gamma firewall config.
 *
 * Data source: https://developers.gamma.app
 *
 * Gamma is an AI-powered presentation and document generation platform.
 * Uses custom "X-API-KEY" header (not Bearer).
 * Token prefix: sk-gamma-
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.gamma.app";
// Token prefix: sk-gamma- (character set and length undocumented)
const PLACEHOLDER_VALUE = "sk-gamma-CoffeeSafeLocalCoffeeSafeLo";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Gamma API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:gamma",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const gammaFirewall = {",
    '  name: "gamma",',
    '  description: "Gamma API",',
    "  placeholders: {",
    `    GAMMA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://public-api.gamma.app",',
    "      auth: {",
    "        headers: {",
    '          "X-API-KEY": "${{ secrets.GAMMA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Gamma firewall config...");
  const ts = generateTypeScript();
  writeOutput("gamma", ts, import.meta.dirname);
}
